  hermesWebConfigSaveSuccess: _('Web 工具后端已保存，建议重启 Hermes Gateway 生效', 'Web tool backend settings saved. Restart Hermes Gateway to take effect.', 'Web 工具後端已儲存，建議重啟 Hermes Gateway 生效'),
