  hermesAgentRuntimeConfigMaxTurns: _('单次运行最大轮数', 'Max turns per run', '單次執行最大輪數'),
  hermesAgentRuntimeConfigGatewayTimeout: _('Gateway 等待超时（秒）', 'Gateway timeout (seconds)', 'Gateway 等待逾時（秒）'),
