  hermesAgentRuntimeConfigApiMaxRetries: _('API 最大重试次数', 'API max retries', 'API 最大重試次數'),
  hermesAgentRuntimeConfigGatewayTimeoutWarning: _('超时预警阈值（秒）', 'Timeout warning threshold (seconds)', '逾時預警閾值（秒）'),
